// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "remix_tests.sol";
import "./AnonymousVerifier.sol";

contract AnonymousVerifierTest {
    AnonymousVerifier verifier;
    
    // Testni koren (Merkle Root) koji postavljamo pri pokretanju
    bytes32 initialRoot = 0x1234567890abcdef1234567890abcdef1234567890abcdef1234567890abcdef;

    // Funkcija koja se pokreće pre svih testova i postavlja ugovor
    uint256 value;
    function beforeEach() public {
        verifier = new AnonymousVerifier(initialRoot);
    }

    // Provera da li je koren ispravno postavljen u konstruktoru
    function testInitialRoot() public {
        Assert.equal(verifier.merkleRoot(), initialRoot, "Koren stabla nije ispravno postavljen!");
    }

    // Provera da li funkcija za azuriranje korena radi kako treba
    function testUpdateRoot() public {
        bytes32 newRoot = 0xabcdef1234567890abcdef1234567890abcdef1234567890abcdef1234567890;
        verifier.updateRoot(newRoot);
        Assert.equal(verifier.merkleRoot(), newRoot, "Azuriranje korena nije uspelo!");
    }
}

